class SensitiveDataFilter(logging.Filter):
    """Filter to prevent sensitive data from appearing in logs."""
    SENSITIVE_PATTERNS = [
        re.compile(r'(token|key|password|secret|session)["\s:=]+\S+', re.IGNORECASE),
        re.compile(r'[A-Za-z0-9+/]{40,}={0,2}'),  # Base64-like strings
    ]

    def filter(self, record: logging.LogRecord) -> bool:
        message = record.getMessage()
        for pattern in self.SENSITIVE_PATTERNS:
            if pattern.search(message):
                record.msg = pattern.sub('[REDACTED]', str(record.msg))
        return True


