    def check_rate_limit(self, user_id: str, max_requests: int = 100, window_seconds: int = 60) -> bool:
        """
        Check and enforce rate limiting for a user.
        Returns True if the request is allowed, False if rate limited.
        """
        try:
            user_id = InputValidator.validate_user_id(user_id)
            if max_requests < 1 or max_requests > 10000:
                raise ValueError("max_requests must be between 1 and 10000.")
            window_seconds = InputValidator.validate_ttl(window_seconds)

            redis_key = f"rate_limit:{user_id}"
            InputValidator.validate_key(redis_key)

            client = self._ensure_connected()

            pipe = client.pipeline(transaction=True)
            pipe.incr(redis_key)
            pipe.ttl(redis_key)
            results = pipe.execute()

            current_count = results[0]
            current_ttl = results[1]

            if current_ttl == -1:
                client.expire(redis_key, window_seconds)

            if current_count > max_requests:
                logger.info(f"Rate limit exceeded for user.")
                return False

            return True

        except ValueError as e:
            logger.warning(f"Validation error in rate limiting: {e}")
            return False
        except RedisError as e:
            logger.error("Redis error in rate limiting.")
            # Fail open or closed based on your security requirements
            # Failing closed is more secure
            return False

